// Filter: only conversations where pending_since is older than 15 seconds
// This ensures we wait for the customer to finish typing
const items = $input.all();
const results = [];
const now = new Date();
const DEBOUNCE_SECONDS = 15;

for (const item of items) {
  const data = item.json;

  // Skip if no pending_since
  if (!data.pending_since) continue;

  const pendingSince = new Date(data.pending_since);
  const ageSeconds = (now.getTime() - pendingSince.getTime()) / 1000;

  // Only process if pending for at least DEBOUNCE_SECONDS
  if (ageSeconds >= DEBOUNCE_SECONDS) {
    results.push({
      json: {
        conversation_id: data.id,
        contact_id: data.contact_id,
        whatsapp_chat_id: data.whatsapp_chat_id,
        bot_paused: data.bot_paused,
        qualification_complete: data.qualification_complete,
        qualification_step: data.qualification_step || 1,
        collected_address: data.collected_address || null,
        collected_wishes: data.collected_wishes || null,
        collected_dimensions: data.collected_dimensions || null,
        collected_phone: data.collected_phone || null,
        collected_photos: data.collected_photos || [],
        pending_since: data.pending_since
      }
    });
  }
}

return results.length > 0 ? results : [];

// Build OpenAI message with ALL new messages batched together
// Get conversation data from the Filter node
const convNode = $('Filter — Ready to Process').first().json;

// Get message history — use .all() to grab every message item
let history;
try {
  const allItems = $('Get Message History').all();
  history = allItems.map(item => item.json);
} catch(e) {
  history = [];
}

const orderedHistory = [...history].reverse();

// Find the last bot message index to separate old history from new messages
let lastBotIndex = -1;
for (let i = orderedHistory.length - 1; i >= 0; i--) {
  if (orderedHistory[i].direction === 'outbound') {
    lastBotIndex = i;
    break;
  }
}

// Old history = everything up to and including last bot message
// New messages = everything after last bot message
const oldHistory = lastBotIndex >= 0 ? orderedHistory.slice(0, lastBotIndex + 1) : [];
const newMessages = lastBotIndex >= 0 ? orderedHistory.slice(lastBotIndex + 1) : orderedHistory;

// Format old history — structured with direction, content, type
const historyStr = oldHistory.map((m, i) => {
  return `[${i + 1}] Direction: ${m.direction} | Type: ${m.type} | Content: ${m.content}`;
}).join('\n');

// Format new messages — structured with direction, content, type
const newMsgStr = newMessages.map((m, i) => {
  const content = m.type === 'image' ? '[Photo attachment]' : m.content;
  return `[${i + 1}] Direction: ${m.direction} | Type: ${m.type} | Content: ${content}`;
}).join('\n');

const hasAnyPhoto = newMessages.some(m => m.type === 'image');

const userMessage = `COLLECTED DATA:
Address: ${convNode.collected_address ?? 'NOT YET COLLECTED'}
Wishes: ${convNode.collected_wishes ?? 'NOT YET COLLECTED'}
Dimensions: ${convNode.collected_dimensions ?? 'NOT YET COLLECTED'}
Photos received: ${Array.isArray(convNode.collected_photos) ? convNode.collected_photos.length : 0}
Phone: ${convNode.collected_phone ?? 'NOT YET COLLECTED'}
Current step: ${convNode.qualification_step ?? 1}

MESSAGE HISTORY:
${historyStr || '(No prior messages)'}

NEW MESSAGES FROM CUSTOMER (sent in quick succession — treat as ONE combined response):
${newMsgStr || '(No new messages)'}

HAS PHOTO ATTACHMENT IN NEW MESSAGES: ${hasAnyPhoto}`;

return [{
  json: {
    userMessage: userMessage,
    conversation_id: convNode.conversation_id,
    contact_id: convNode.contact_id,
    whatsapp_chat_id: convNode.whatsapp_chat_id,
    qualification_step: convNode.qualification_step,
    collected_address: convNode.collected_address,
    collected_wishes: convNode.collected_wishes,
    collected_dimensions: convNode.collected_dimensions,
    collected_phone: convNode.collected_phone,
    collected_photos: convNode.collected_photos
  }
}];

// Parse & Validate AI Response
const convData = $node['Build OpenAI Message'].json;
let aiOutput;
try {
  // Get raw content
  let rawContent = $input.first().json.message?.content 
                || $input.first().json.choices?.[0]?.message?.content 
                || $input.first().json.text 
                || '';

  // Check if already an object or needs parsing
  if (typeof rawContent === 'object' && rawContent !== null) {
    aiOutput = rawContent;
  } else {
    aiOutput = JSON.parse(rawContent);
  }

  // Validate required structure
  if (!aiOutput.messages || !Array.isArray(aiOutput.messages) || aiOutput.messages.length === 0) {
    throw new Error('Missing or empty messages array');
  }
  if (typeof aiOutput.currentStep === 'undefined') {
    aiOutput.currentStep = convData.qualification_step || 1;
  }
  if (typeof aiOutput.qualificationComplete === 'undefined') {
    aiOutput.qualificationComplete = false;
  }
  if (!aiOutput.extracted) {
    aiOutput.extracted = {};
  }
} catch (e) {
  aiOutput = {
    messages: ['Er is een fout opgetreden. Probeer het opnieuw.'],
    extracted: {},
    currentStep: convData.qualification_step || 1,
    qualificationComplete: false
  };
}

return [{
  json: {
    ai_messages: aiOutput.messages,
    ai_reply: aiOutput.messages[0],
    extracted_address: aiOutput.extracted.address || null,
    extracted_wishes: aiOutput.extracted.wishes || null,
    extracted_dimensions: aiOutput.extracted.dimensions || null,
    extracted_hasPhoto: aiOutput.extracted.hasPhoto || false,
    extracted_phone: aiOutput.extracted.phone || null,
    currentStep: aiOutput.currentStep,
    qualificationComplete: aiOutput.qualificationComplete,
    conversation_id: convData.conversation_id,
    contact_id: convData.contact_id,
    whatsapp_chat_id: convData.whatsapp_chat_id,
    collected_address: convData.collected_address,
    collected_wishes: convData.collected_wishes,
    collected_dimensions: convData.collected_dimensions,
    collected_phone: convData.collected_phone,
    collected_photos: convData.collected_photos
  }
}];

// Calculate Human-like Delay
const aiReply = $node['Parse AI Response'].json.ai_reply || '';
const messageLength = aiReply.length;

let delay = 2000 + (messageLength * 30) + (Math.random() * 2000);
delay = Math.min(delay, 10000);
delay = Math.max(delay, 1500);

return [{
  json: {
    delay_ms: Math.floor(delay),
    delay_seconds: Math.floor(delay / 1000),
    message: aiReply,
    conversation_id: $node['Parse AI Response'].json.conversation_id,
    whatsapp_chat_id: $node['Parse AI Response'].json.whatsapp_chat_id,
    qualificationComplete: $node['Parse AI Response'].json.qualificationComplete
  }
}];
